mapper.select:
SELECT refund_order_id AS refundOrderId, payment_order_id AS paymentOrderId, order_no AS orderNo, customer_name AS customerName, CONCAT('¥', FORMAT(refund_amount, 2)) AS refundAmount, refund_method AS refundMethod, status, status_type AS statusType, DATE_FORMAT(applied_at, '%Y-%m-%d %H:%i:%s') AS appliedAt, CASE WHEN success_at IS NULL THEN '-' ELSE DATE_FORMAT(success_at, '%Y-%m-%d %H:%i:%s') END AS successAt FROM t_refund_order
refund_order_id LIKE CONCAT('%', #{query.refundOrderId}, '%')
AND payment_order_id LIKE CONCAT('%', #{query.paymentOrderId}, '%')
AND status = #{query.refundStatus}
AND refund_method = #{query.refundMethod}
ORDER BY applied_at DESC
